package com.maum.backend.service

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.repository.follow.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

@Service
class UserService(
    private val userRepository: UserRepository,
    private val followRepository: FollowRepository,
) {

    @Transactional
    fun follow(followerId: String, followingId: String) {
        // 자기 자신 팔로우 방지
        require(followerId != followingId) {
            "자기 자신을 팔로우할 수 없습니다."
        }

        // 팔로우 대상 사용자 존재 확인
        userRepository.findById(followingId).orElseThrow {
            NoSuchElementException("사용자를 찾을 수 없습니다. id=$followingId")
        }

        // 팔로워 사용자 존재 확인
        userRepository.findById(followerId).orElseThrow {
            NoSuchElementException("사용자를 찾을 수 없습니다. id=$followerId")
        }

        // 중복 팔로우 방지
        check(!followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)) {
            "이미 팔로우한 사용자입니다."
        }

        followRepository.save(
            FollowEntity(
                followerId = followerId,
                followingId = followingId,
            )
        )
    }

    @Transactional
    fun unfollow(followerId: String, followingId: String) {
        val follow = followRepository.findByFollowerIdAndFollowingId(followerId, followingId)
            ?: throw NoSuchElementException("팔로우 관계가 존재하지 않습니다.")

        followRepository.delete(follow)
    }

    @Transactional(readOnly = true)
    fun getFollowings(userId: String): List<FollowEntity> {
        return followRepository.findAllByFollowerId(userId)
    }

    @Transactional(readOnly = true)
    fun getFollowers(userId: String): List<FollowEntity> {
        return followRepository.findAllByFollowingId(userId)
    }
}
```

