import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.entity.user.UserEntity
import com.maum.backend.repository.follow.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.never
import org.mockito.Mockito.verify
import org.mockito.junit.jupiter.MockitoExtension
import org.mockito.kotlin.any
import org.mockito.kotlin.whenever
import java.util.Optional

@ExtendWith(MockitoExtension::class)
class UserServiceTest {

    @Mock
    private lateinit var userRepository: UserRepository

    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var userService: UserService

    // ─────────────────────────────────────────────
    // follow()
    // ─────────────────────────────────────────────

    @Test
    fun `should follow successfully when valid follower and following`() {
        // given
        val followerId = "user-001"
        val followingId = "user-002"

        val followerEntity = UserEntity(id = followerId, nickname = "팔로워")
        val followingEntity = UserEntity(id = followingId, nickname = "팔로잉대상")
        val savedFollow = FollowEntity(id = "follow-001", followerId = followerId, followingId = followingId)

        whenever(userRepository.findById(followingId)).thenReturn(Optional.of(followingEntity))
        whenever(userRepository.findById(followerId)).thenReturn(Optional.of(followerEntity))
        whenever(followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)).thenReturn(false)
        whenever(followRepository.save(any())).thenReturn(savedFollow)

        // when
        userService.follow(followerId, followingId)

        // then
        verify(followRepository).existsByFollowerIdAndFollowingId(followerId, followingId)
        verify(followRepository).save(any())
    }

    @Test
    fun `should throw IllegalArgumentException when following self`() {
        // given
        val userId = "user-001"

        // when & then
        val exception = assertThrows<IllegalArgumentException> {
            userService.follow(userId, userId)
        }

        assertThat(exception.message).contains("자기 자신을 팔로우할 수 없습니다")
        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should throw NoSuchElementException when following user does not exist`() {
        // given
        val followerId = "user-001"
        val followingId = "user-999"

        whenever(userRepository.findById(followingId)).thenReturn(Optional.empty())

        // when & then
        val exception = assertThrows<NoSuchElementException> {
            userService.follow(followerId, followingId)
        }

        assertThat(exception.message).contains(followingId)
        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should throw NoSuchElementException when follower user does not exist`() {
        // given
        val followerId = "user-999"
        val followingId = "user-002"

        val followingEntity = UserEntity(id = followingId, nickname = "팔로잉대상")
        whenever(userRepository.findById(followingId)).thenReturn(Optional.of(followingEntity))
        whenever(userRepository.findById(followerId)).thenReturn(Optional.empty())

        // when & then
        val exception = assertThrows<NoSuchElementException> {
            userService.follow(followerId, followingId)
        }

        assertThat(exception.message).contains(followerId)
        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should throw IllegalStateException when already following`() {
        // given
        val followerId = "user-001"
        val followingId = "user-002"

        val followerEntity = UserEntity(id = followerId, nickname = "팔로워")
        val followingEntity = UserEntity(id = followingId, nickname = "팔로잉대상")

        whenever(userRepository.findById(followingId)).thenReturn(Optional.of(followingEntity))
        whenever(userRepository.findById(followerId)).thenReturn(Optional.of(followerEntity))
        whenever(followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)).thenReturn(true)

        // when & then
        val exception = assertThrows<IllegalStateException> {
            userService.follow(followerId, followingId)
        }

        assertThat(exception.message).contains("이미 팔로우한 사용자")
        verify(followRepository, never()).save(any())
    }

    // ─────────────────────────────────────────────
    // unfollow()
    // ─────────────────────────────────────────────

    @Test
    fun `should unfollow successfully when follow relationship exists`() {
        // given
        val followerId = "user-001"
        val followingId = "user-002"
        val followEntity = FollowEntity(id = "follow-001", followerId = followerId, followingId = followingId)

        whenever(followRepository.findByFollowerIdAndFollowingId(followerId, followingId))
            .thenReturn(followEntity)

        // when
        userService.unfollow(followerId, followingId)

        // then
        verify(followRepository).findByFollowerIdAndFollowingId(followerId, followingId)
        verify(followRepository).delete(followEntity)
    }

    @Test
    fun `should throw NoSuchElementException when unfollow relationship does not exist`() {
        // given
        val followerId = "user-001"
        val followingId = "user-002"

        whenever(followRepository.findByFollowerIdAndFollowingId(followerId, followingId))
            .thenReturn(null)

        // when & then
        val exception = assertThrows<NoSuchElementException> {
            userService.unfollow(followerId, followingId)
        }

        assertThat(exception.message).contains("팔로우 관계가 존재하지 않습니다")
        verify(followRepository, never()).delete(any())
    }

    // ─────────────────────────────────────────────
    // getFollowings()
    // ─────────────────────────────────────────────

    @Test
    fun `should return followings list when user has followings`() {
        // given
        val userId = "user-001"
        val followings = listOf(
            FollowEntity(id = "f-1", followerId = userId, followingId = "user-002"),
            FollowEntity(id = "f-2", followerId = userId, followingId = "user-003"),
        )

        whenever(followRepository.findAllByFollowerId(userId)).thenReturn(followings)

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result.map { it.followingId }).containsExactlyInAnyOrder("user-002", "user-003")
        verify(followRepository).findAllByFollowerId(userId)
    }

    @Test
    fun `should return empty list when user has no followings`() {
        // given
        val userId = "user-001"

        whenever(followRepository.findAllByFollowerId(userId)).thenReturn(emptyList())

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).isEmpty()
    }

    // ─────────────────────────────────────────────
    // getFollowers()
    // ─────────────────────────────────────────────

    @Test
    fun `should return followers list when user has followers`() {
        // given
        val userId = "user-002"
        val followers = listOf(
            FollowEntity(id = "f-1", followerId = "user-001", followingId = userId),
            FollowEntity(id = "f-2", followerId = "user-003", followingId = userId),
        )

        whenever(followRepository.findAllByFollowingId(userId)).thenReturn(followers)

        // when
        val result = userService.getFollowers(userId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result.map { it.followerId }).containsExactlyInAnyOrder("user-001", "user-003")
        verify(followRepository).findAllByFollowingId(userId)
